// Auto-generated — Montserrat font + NUE logo for jsPDF
import jsPDF from "jspdf";

const MONTSERRAT_REGULAR = "";

const MONTSERRAT_BOLD = "";

const MONTSERRAT_ITALIC = "";

const NUE_LOGO = "data:image/png;base64,";

export function setupPdfDoc(doc: jsPDF) {
  doc.addFileToVFS("Montserrat-Regular.ttf", MONTSERRAT_REGULAR);
  doc.addFont("Montserrat-Regular.ttf", "Montserrat", "normal");
  doc.addFileToVFS("Montserrat-Bold.ttf", MONTSERRAT_BOLD);
  doc.addFont("Montserrat-Bold.ttf", "Montserrat", "bold");
  doc.addFileToVFS("Montserrat-Italic.ttf", MONTSERRAT_ITALIC);
  doc.addFont("Montserrat-Italic.ttf", "Montserrat", "italic");
  doc.setFont("Montserrat", "normal");
}

export function addPdfHeader(doc: jsPDF, rightText?: string) {
  // Logo
  doc.addImage(NUE_LOGO, "PNG", 14, 8, 40, 16);

  // Subtitle
  doc.setFontSize(9);
  doc.setFont("Montserrat", "normal");
  doc.setTextColor(100);
  doc.text("Marmoraria Premium — Recife/PE", 14, 28);
  doc.setTextColor(0);

  // Right code
  if (rightText) {
    doc.setFontSize(14);
    doc.setFont("Montserrat", "bold");
    doc.text(rightText, 196, 18, { align: "right" });
  }

  doc.setDrawColor(200);
  doc.line(14, 32, 196, 32);
}
